codeExercises.solution:
import express from 'express';
const router = express.Router();

const validationMiddleware = (req, res, next) => { console.log('Validated!'); next(); };
const registerService = async (data) => ({ id: 1, email: data.email });

const registerController = async (req, res) => {
  try {
    const newUser = await registerService(req.body);
    res.status(201).json(newUser);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

router.post('/register', validationMiddleware, registerController);

export default router;
